  return (  
       
         <div> 

<div className={`${classes.up} ${classes.hm1}`}>  </div>
<div className={`${classes.down} ${classes.hm1}`}>  </div>

<div className={classes.right}>
  
  <div className={`${classes.r1} ${classes.hm1}`}>  </div>
  <div className={`${classes.r2} ${classes.hm1}`}> </div>
  <div className={`${classes.r3} ${classes.hm1}`}> </div>
  <div className={`${classes.r4} ${classes.hm1}`}> </div>


  
  
    </div>



         </div> 
  )
};

export default Aboutp
